BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?type ?name WHERE {
  <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Error%2520Budgets::Pupil%2520Alignment%2520Error%2520Budget> vocab:Element_ownedElement+ ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name WHERE {
  <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Error%2520Budgets::Pupil%2520Alignment%2520Error%2520Budget> vocab:Element_ownedElement+ ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
  FILTER(?type != vocab:association && ?type != vocab:property)
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?assoc ?end1 ?end2 ?role1 ?role2 ?name1 ?name2 WHERE {
  <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Error%2520Budgets::Pupil%2520Alignment%2520Error%2520Budget> vocab:Element_ownedElement+ ?assoc .
  ?assoc rdf:type vocab:association .
  ?assoc vocab:Association_memberEnd ?end1 .
  ?assoc vocab:Association_memberEnd ?end2 .
  OPTIONAL { ?end1 vocab:ConnectorEnd_role ?role1 }
  OPTIONAL { ?end2 vocab:ConnectorEnd_role ?role2 }
  OPTIONAL { ?role1 vocab:NamedElement_name ?name1 }
  OPTIONAL { ?role2 vocab:NamedElement_name ?name2 }
}
LIMIT 50

